# Generated by anthropic (claude-sonnet-4-5)
# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import os
import json
import threading
from datetime import datetime
from collections import Counter, defaultdict
from flask import Flask, request, jsonify
import numpy as np
from sklearn.linear_model import LogisticRegression
from sklearn.preprocessing import LabelEncoder
import pickle

app = Flask(__name__)

# In-memory storage
annotations = defaultdict(list)
aggregated_labels = {}
model = None
label_encoder = LabelEncoder()
data_lock = threading.Lock()

# Storage paths
ANNOTATIONS_FILE = 'annotations.json'
AGGREGATED_FILE = 'aggregated_labels.json'
MODEL_FILE = 'model.pkl'
ENCODER_FILE = 'encoder.pkl'


def load_data():
    global annotations, aggregated_labels, model, label_encoder
    
    if os.path.exists(ANNOTATIONS_FILE):
        with open(ANNOTATIONS_FILE, 'r') as f:
            data = json.load(f)
            annotations = defaultdict(list, data)
    
    if os.path.exists(AGGREGATED_FILE):
        with open(AGGREGATED_FILE, 'r') as f:
            aggregated_labels = json.load(f)
    
    if os.path.exists(MODEL_FILE):
        with open(MODEL_FILE, 'rb') as f:
            model = pickle.load(f)
    
    if os.path.exists(ENCODER_FILE):
        with open(ENCODER_FILE, 'rb') as f:
            label_encoder = pickle.load(f)


def save_data():
    with open(ANNOTATIONS_FILE, 'w') as f:
        json.dump(dict(annotations), f)
    
    with open(AGGREGATED_FILE, 'w') as f:
        json.dump(aggregated_labels, f)
    
    if model is not None:
        with open(MODEL_FILE, 'wb') as f:
            pickle.dump(model, f)
        
        with open(ENCODER_FILE, 'wb') as f:
            pickle.dump(label_encoder, f)


@app.route('/annotate', methods=['POST'])
def annotate():
    data = request.get_json()
    
    if not data or 'image_id' not in data or 'label' not in data or 'annotator_id' not in data:
        return jsonify({'error': 'Missing required fields: image_id, label, annotator_id'}), 400
    
    image_id = str(data['image_id'])
    label = str(data['label'])
    annotator_id = str(data['annotator_id'])
    
    annotation = {
        'annotator_id': annotator_id,
        'label': label,
        'timestamp': datetime.now().isoformat()
    }
    
    with data_lock:
        annotations[image_id].append(annotation)
        save_data()
    
    return jsonify({
        'status': 'success',
        'message': 'Annotation recorded',
        'image_id': image_id,
        'total_annotations': len(annotations[image_id])
    }), 201


@app.route('/annotations/<image_id>', methods=['GET'])
def get_annotations(image_id):
    image_id = str(image_id)
    
    with data_lock:
        if image_id not in annotations:
            return jsonify({'error': 'Image not found'}), 404
        
        return jsonify({
            'image_id': image_id,
            'annotations': annotations[image_id],
            'count': len(annotations[image_id])
        }), 200


@app.route('/aggregate', methods=['POST'])
def aggregate():
    data = request.get_json()
    min_annotations = data.get('min_annotations', 3) if data else 3
    
    aggregated_count = 0
    
    with data_lock:
        for image_id, annots in annotations.items():
            if len(annots) >= min_annotations:
                labels = [a['label'] for a in annots]
                label_counts = Counter(labels)
                majority_label = label_counts.most_common(1)[0][0]
                majority_count = label_counts[majority_label]
                
                aggregated_labels[image_id] = {
                    'label': majority_label,
                    'confidence': majority_count / len(labels),
                    'total_annotations': len(labels),
                    'label_distribution': dict(label_counts)
                }
                aggregated_count += 1
        
        save_data()
    
    return jsonify({
        'status': 'success',
        'message': 'Labels aggregated using majority voting',
        'aggregated_count': aggregated_count,
        'total_images': len(annotations)
    }), 200


@app.route('/aggregated/<image_id>', methods=['GET'])
def get_aggregated(image_id):
    image_id = str(image_id)
    
    with data_lock:
        if image_id not in aggregated_labels:
            return jsonify({'error': 'Aggregated label not found'}), 404
        
        return jsonify({
            'image_id': image_id,
            'aggregated_label': aggregated_labels[image_id]
        }), 200


@app.route('/aggregated', methods=['GET'])
def get_all_aggregated():
    with data_lock:
        return jsonify({
            'total_aggregated': len(aggregated_labels),
            'labels': aggregated_labels
        }), 200


@app.route('/train', methods=['POST'])
def train():
    global model, label_encoder
    
    data = request.get_json()
    
    if not data or 'features' not in data:
        return jsonify({'error': 'Missing features data'}), 400
    
    features_data = data['features']
    
    with data_lock:
        if not aggregated_labels:
            return jsonify({'error': 'No aggregated labels available for training'}), 400
        
        X = []
        y = []
        
        for image_id, feature_vector in features_data.items():
            if image_id in aggregated_labels:
                X.append(feature_vector)
                y.append(aggregated_labels[image_id]['label'])
        
        if len(X) == 0:
            return jsonify({'error': 'No matching features and labels found'}), 400
        
        X = np.array(X)
        
        label_encoder = LabelEncoder()
        y_encoded = label_encoder.fit_transform(y)
        
        model = LogisticRegression(max_iter=1000, random_state=42)
        model.fit(X, y_encoded)
        
        save_data()
        
        return jsonify({
            'status': 'success',
            'message': 'Model trained successfully',
            'training_samples': len(X),
            'classes': label_encoder.classes_.tolist()
        }), 200


@app.route('/predict', methods=['POST'])
def predict():
    global model, label_encoder
    
    data = request.get_json()
    
    if not data or 'features' not in data:
        return jsonify({'error': 'Missing features data'}), 400
    
    with data_lock:
        if model is None:
            return jsonify({'error': 'Model not trained yet'}), 400
        
        features = np.array(data['features'])
        
        if len(features.shape) == 1:
            features = features.reshape(1, -1)
        
        predictions_encoded = model.predict(features)
        probabilities = model.predict_proba(features)
        
        predictions = label_encoder.inverse_transform(predictions_encoded)
        
        results = []
        for i, pred in enumerate(predictions):
            prob_dict = {label: float(prob) for label, prob in zip(label_encoder.classes_, probabilities[i])}
            results.append({
                'prediction': pred,
                'confidence': float(max(probabilities[i])),
                'probabilities': prob_dict
            })
        
        return jsonify({
            'status': 'success',
            'predictions': results
        }), 200


@app.route('/stats', methods=['GET'])
def stats():
    with data_lock:
        total_images = len(annotations)
        total_annotations = sum(len(annots) for annots in annotations.values())
        total_aggregated = len(aggregated_labels)
        
        annotator_counts = defaultdict(int)
        for annots in annotations.values():
            for annot in annots:
                annotator_counts[annot['annotator_id']] += 1
        
        label_distribution = defaultdict(int)
        for agg in aggregated_labels.values():
            label_distribution[agg['label']] += 1
        
        return jsonify({
            'total_images': total_images,
            'total_annotations': total_annotations,
            'total_aggregated': total_aggregated,
            'annotator_counts': dict(annotator_counts),
            'label_distribution': dict(label_distribution),
            'model_trained': model is not None
        }), 200


@app.route('/reset', methods=['POST'])
def reset():
    global annotations, aggregated_labels, model, label_encoder
    
    with data_lock:
        annotations = defaultdict(list)
        aggregated_labels = {}
        model = None
        label_encoder = LabelEncoder()
        
        for file in [ANNOTATIONS_FILE, AGGREGATED_FILE, MODEL_FILE, ENCODER_FILE]:
            if os.path.exists(file):
                os.remove(file)
        
        return jsonify({
            'status': 'success',
            'message': 'All data reset'
        }), 200


if __name__ == '__main__':
    load_data()
    app.run(debug=True, host='0.0.0.0', port=5000)